class Solution:
    def isValidSudoku(self, board: list[list[int]]) -> bool:
        for i in range(9):
            row = set(board[i])
            col = set(board[j][i] for j in range(9))
            subgrid = set(board[i // 3 * 3 + j // 3][i % 3 * 3 + j % 3] for j in range(9))
            if len(row) != 9 or len(col) != 9 or len(subgrid) != 9:
                return False
        return True

def main():
